        // for the freed old block (and ensure we don't keep temp slot accounting).
        a->stats.allocated -= old_pay;

        // Drop the temporary slot bookkeeping without freeing its block.
        a->slot_live[nidx] = 0;
        a->slot_payload[nidx] = 0;
        a->slots[nidx] = NULL;
        a->stats.live_blocks--;

        // Now actually free the old block in the heap.
        free_block_for_ptr(a, old_ptr);

        return idx;
