#include "../include/arena.h"
#include "../list_b/list.h"
#include "../pool_a/tag.h"
#include "../split_c/split.h"

static void adjust_payload(Arena *a, int idx, size_t req) {
    size_t old = a->slot_payload[idx];
    a->slot_payload[idx] = req;
    if (req > old) a->stats.allocated += (req - old);
    else a->stats.allocated -= (old - req);
    if (a->stats.allocated > a->stats.peak) a->stats.peak = a->stats.allocated;
}

int split_realloc_inplace(Arena *a, Block *oldb, int idx, size_t req) {
    size_t old_total = tag_read_size(oldb);
    size_t need = blk_align(req + HDR_SIZE + FTR_SIZE);

    if (old_total < need + MIN_BLK) {
        adjust_payload(a, idx, req);
        return idx;
    }

    // Turn the whole block into free, coalesce (no-op for allocated neighbors), then split.
    z_set_flag(oldb, 0);
    list_coalesce(a, oldb);
    mark_c(a, oldb, req);

    adjust_payload(a, idx, req);
    return idx;
}

int split_grow_inplace(Arena *a, Block *oldb, int idx, size_t req, size_t need) {
    size_t merged;

    if (q8f_blk(a, oldb, need, &merged) != 0) {
        return -1;
    }

    // q8f_blk has ensured we can grow by absorbing adjacent free space.
    // Ensure the header reflects the merged extent and mark allocated.
    xa0(oldb, merged);
    z_set_flag(oldb, 1);

    // If there is enough remainder, split and return tail to free list.
    if (merged >= need + MIN_BLK) {
        mark_c(a, oldb, req);
    }

    adjust_payload(a, idx, req);
    return idx;
}

void slot_take_split(Arena *a, Block *fit, size_t req, size_t need) {
    (void)need;
    mark_c(a, fit, req);
}
EOF
