static void adjust_payload(Arena *a, int idx, size_t req) {
    size_t old = a->slot_payload[idx];
    a->slot_payload[idx] = req;
    if (req > old) {
        a->stats.allocated += (req - old);
    } else {
        a->stats.allocated -= (old - req);
    }
    if (a->stats.allocated > a->stats.peak) {
        a->stats.peak = a->stats.allocated;
    }
}

int split_realloc_inplace(Arena *a, Block *oldb, int idx, size_t req) {
    size_t old_total = tag_read_size(oldb);
    size_t need = blk_align(req + HDR_SIZE + FTR_SIZE);

    // If we can't split, just update the tracked payload size.
    if (old_total < need + MIN_BLK) {
        adjust_payload(a, idx, req);
        return idx;
    }

    // Split the block in-place to create a new free tail.
    z_set_flag(oldb, 0);
    list_coalesce(a, oldb);
    mark_c(a, oldb, req);

    adjust_payload(a, idx, req);
    return idx;
}

int split_grow_inplace(Arena *a, Block *oldb, int idx, size_t req, size_t need) {
    size_t merged;

    if (q8f_blk(a, oldb, need, &merged) != 0) {
        return -1;
    }

    if (merged >= need + MIN_BLK) {
        // Consume merged region and split remainder.
        z_set_flag(oldb, 0);
        list_coalesce(a, oldb);
        mark_c(a, oldb, req);
    } else {
        // Consume entire merged region.
        if (on_fl(a, oldb->off)) {
            list_remove(a, oldb);
        }
        xa0(oldb, merged);
        z_set_flag(oldb, 1);
    }

    adjust_payload(a, idx, req);
    return idx;
}

void slot_take_split(Arena *a, Block *fit, size_t req, size_t need) {
    (void)need;
    mark_c(a, fit, req);
}
