        return -1;
    }
    fprintf(fp, "{\n  \"cases\": [\n");
    for (i = 0; i < count; i++) {
        write_case(fp, &cases[i], i + 1 == count);
    }
    fprintf(fp, "  ]\n}\n");
    fclose(fp);
    return 0;
}
