int arena_slot_realloc(Arena *a, int idx, size_t req) {
    if (idx < 0 || idx >= a->slot_count || !a->slot_live[idx]) {
        return -1;
    }

    Block oldb;
    size_t old_pay = a->slot_payload[idx];
    size_t need = blk_align(req + HDR_SIZE + FTR_SIZE);

    oldb.base = a->mem;
    oldb.off = (size_t)((unsigned char *)a->slots[idx] - a->mem - HDR_SIZE);

    // In-place shrink.
    if (need <= tag_read_size(&oldb)) {
        (void)split_realloc_inplace(a, &oldb, idx, req);
        return idx;
    }

    // In-place grow by merging neighbor if possible.
    if (split_grow_inplace(a, &oldb, idx, req, need) >= 0) {
        return idx;
    }

    // Move: keep the same logical slot index.
    {
        void *old_ptr = a->slots[idx];
        int nidx = arena_slot_alloc(a, req);
        if (nidx < 0) {
            return -1;
        }

        // Copy old payload into new block.
        xc2(a->slots[nidx], old_ptr, old_pay);

        // Adopt the new block into the original slot.
        a->slots[idx] = a->slots[nidx];
        a->slot_payload[idx] = req;

        // Fix payload accounting: alloc added +req; we still need to remove old_pay
        // for the freed old block (and ensure we don't keep temp slot accounting).
        a->stats.allocated -= old_pay;

        // Drop the temporary slot bookkeeping without freeing its block.
        a->slot_live[nidx] = 0;
        a->slot_payload[nidx] = 0;
        a->slots[nidx] = NULL;
        a->stats.live_blocks--;

        // Now actually free the old block in the heap.
        free_block_for_ptr(a, old_ptr);

        return idx;
    }
}
